def get_merina_caste_info():
    castes = {
        "Andriana": "The nobles, occupying the highest rank in the Merina Kingdom.",
        "Hova": "The free commoners who managed rice and crop lands and engaged in trading.",
        "Andevo": "The slaves, also called Mainty, who performed labor on farms and were denied land ownership."
    }
    return castes

# Example usage:
caste_info = get_merina_caste_info()
for caste, description in caste_info.items():
    print(f"{caste}: {description}")
